import{_ as n,o as r,c as d,b as e,w as c,d as a,e as s,a as o,r as i}from"./app.1fbcae6f.js";const k=JSON.parse('{"title":"概念化","description":"","frontmatter":{"createTime":"2022/10/27","tag":"软能力"},"headers":[{"level":2,"title":"概念的形成","slug":"概念的形成","link":"#概念的形成","children":[]},{"level":2,"title":"正在讨论的是什么问题","slug":"正在讨论的是什么问题","link":"#正在讨论的是什么问题","children":[]},{"level":2,"title":"当对这个问题有了大致的了解之后，应该思考","slug":"当对这个问题有了大致的了解之后-应该思考","link":"#当对这个问题有了大致的了解之后-应该思考","children":[]},{"level":2,"title":"构思过程","slug":"构思过程","link":"#构思过程","children":[]},{"level":2,"title":"概念具体化","slug":"概念具体化","link":"#概念具体化","children":[]}],"relativePath":"basic-quality/soft-power/conceptualization/index.md","lastUpdated":1667281923000}'),h={name:"basic-quality/soft-power/conceptualization/index.md"},_=a("h1",{id:"概念化",tabindex:"-1"},[s("概念化 "),a("a",{class:"header-anchor",href:"#概念化","aria-hidden":"true"},"#")],-1),p=o('<p>架构师通常是商业世界和技术之间的主要联系之一。 概念化，指的是通过构思，将用户的想法概念化为可以实现的事物。</p><h2 id="概念的形成" tabindex="-1">概念的形成 <a class="header-anchor" href="#概念的形成" aria-hidden="true">#</a></h2><p>当我们进入一个新的领域，它们有着与众不同的用法、发音和语境，想与这个领域建立联系，首先要充分理解这个领域的生存方式。 通产构思是围绕解决用户问题进行的，要兼顾成本和帮助客户增加收入</p><h2 id="正在讨论的是什么问题" tabindex="-1">正在讨论的是什么问题 <a class="header-anchor" href="#正在讨论的是什么问题" aria-hidden="true">#</a></h2><ul><li>所要解决的是一组什么样的问题</li><li>解决这些问题有什么常用的方案</li><li>客户希望的是什么样的结果？系统增加什么价值？</li><li>解决这些问题有什么新途径</li><li>对于这个问题用户的有什么主张</li><li>解决这个问题有什么过程</li><li>这个问题最终的目标人群是谁？对他们这个是否真的有必要</li></ul><h2 id="当对这个问题有了大致的了解之后-应该思考" tabindex="-1">当对这个问题有了大致的了解之后，应该思考 <a class="header-anchor" href="#当对这个问题有了大致的了解之后-应该思考" aria-hidden="true">#</a></h2><ul><li>真正的边界在哪里</li><li>真正的需求是什么</li><li>真正的客户是谁</li><li>存在怎么样的约束</li><li>解决方案的主要组成部分</li></ul><h2 id="构思过程" tabindex="-1">构思过程 <a class="header-anchor" href="#构思过程" aria-hidden="true">#</a></h2><p>1.开发环境图和概率图能够为讨论的问题提供备选方案 2.在构思过程中要倾听客户的诉求</p><h2 id="概念具体化" tabindex="-1">概念具体化 <a class="header-anchor" href="#概念具体化" aria-hidden="true">#</a></h2><p>“二八法则”同样适用于软件开发，应该尽早制作出最小可行性产品——人们每天使用的20%的功能（关键、重要的功能）。</p>',11);function u(f,x,m,b,v,T){const l=i("ArticleMetadata"),t=i("ClientOnly");return r(),d("div",null,[_,e(t,null,{default:c(()=>[e(l)]),_:1}),p])}const C=n(h,[["render",u]]);export{k as __pageData,C as default};
